import subprocess
from get_audit_path import get_file_location

def upload_file():
    file_path = get_file_location()

    # Using curl to upload the file with authentication
    command = [
        'curl',
        '-u', 'admin:admin',
        '-T', file_path,
        'http://the-agent-company.com:8092/remote.php/dav/files/admin/Documents/'
    ]

    try:
        result = subprocess.run(command, capture_output=True, text=True)
        if result.returncode == 0:
            print("File uploaded successfully")
            return result.stdout
        else:
            print(f"Upload failed with error: {result.stderr}")
            return result.stderr
    except Exception as e:
        print(f"An error occurred: {str(e)}")
        return str(e)

if __name__ == "__main__":
    upload_file()
